mapper.select:
SELECT vol.id AS id, vol.school_id AS schoolId, vol.school_year AS schoolYear, grade.id AS gradeId, vol.grade_name AS gradeName, vol.class_id AS classId, vol.class_name AS className, vol.student_id AS studentId, stu.chinese_name AS studentName, stu.seat_no AS seatNo, vol.activity_name AS activityName, vol.organization AS organization, vol.service_date AS serviceDate, vol.start_time AS startTime, vol.end_time AS endTime, vol.service_nature AS serviceNature, vol.service_type AS serviceType, vol.service_seconds AS serviceSeconds FROM volunteer_service vol LEFT JOIN student_info stu ON stu.id = vol.student_id LEFT JOIN sys_class cla ON cla.id = vol.class_id LEFT JOIN grade_group grade ON grade.id = cla.grade_group WHERE vol.deleted = 0
AND vol.school_id = #{reqModel.schoolId}
AND vol.school_year = #{reqModel.schoolYear}
AND vol.class_id = #{reqModel.classId}
AND vol.student_id = #{reqModel.studentId}
AND vol.activity_name LIKE CONCAT('%', #{reqModel.activityName}, '%')
AND vol.service_date >= #{reqModel.serviceDateStart}
AND vol.service_date <= #{reqModel.serviceDateEnd}
AND vol.class_id IN
#{classId}
ORDER BY id DESC

SELECT
    vol.service_date   AS serviceDate,
    vol.service_seconds   AS serviceSeconds
FROM volunteer_service vol
WHERE vol.deleted = 0
    AND vol.school_id = #{schoolId}
    AND vol.school_year = #{schoolYear}
    AND vol.student_id = #{studentId}
